message.content:
=Rispondi a questa domanda come farebbe un utente che cerca dove dormire in Romagna:

{{ $json.Domande }}

Cerca informazioni specifiche su strutture ricettive, appartamenti e alloggi nelle colline romagnole, in particolare nell'area di Bertinoro, Forlì e Cesena. Elenca i nomi delle strutture che menzioni.

parameters.jsCode:
const testo = $input.first().json.content[0].text;

const data = new Date().toLocaleDateString('it-IT');
const dataISO = new Date().toISOString().slice(0,10);
const nomeFile = `report-geo-aeo-casa-cavour-${dataISO}.html`;

// Conversione markdown → HTML
let html = testo
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/━+/g, '<hr class="separator">')
  .replace(/^### (.+)$/gm, '<h3>$1</h3>')
  .replace(/^## (.+)$/gm, '<h2>$1</h2>')
  .replace(/^# (.+)$/gm, '<h1>$1</h1>')
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  .replace(/\*(.+?)\*/g, '<em>$1</em>')
  .replace(/^&gt; (.+)$/gm, '<blockquote>$1</blockquote>')
  .replace(/^- (.+)$/gm, '<li>$1</li>')
  .replace(/✅/g, '<span class="presente">✅</span>')
  .replace(/❌/g, '<span class="assente">❌</span>')
  .replace(/📊/g, '📊')
  .replace(/🏆/g, '🏆')
  .replace(/🎯/g, '🎯')
  .replace(/\n\n/g, '</p><p>')
  .replace(/\n/g, '<br>');

const documento = `<!DOCTYPE html>
<html lang="it">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Report GEO/AEO Casa Cavour — ${data}</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Georgia, serif; max-width: 860px; margin: 40px auto; padding: 0 24px 60px; color: #1a1a1a; background: #fafaf8; line-height: 1.8; }
  .header { background: #a0782a; color: white; padding: 28px 36px; border-radius: 10px; margin-bottom: 2.5em; }
  .header h1 { color: white; font-size: 1.6em; border-bottom: 1px solid rgba(255,255,255,0.35); padding-bottom: 10px; margin-bottom: 10px; }
  .header p { color: rgba(255,255,255,0.85); font-size: 0.9em; font-family: sans-serif; }
  h2 { color: #a0782a; margin-top: 2em; margin-bottom: 0.5em; font-size: 1.2em; }
  h3 { color: #333; margin-top: 1.5em; margin-bottom: 0.4em; font-size: 1.05em; }
  hr.separator { border: none; border-top: 2px solid #a0782a; margin: 1.8em 0; }
  blockquote { background: #fff8f0; border-left: 4px solid #a0782a; margin: 1.2em 0; padding: 14px 22px; border-radius: 0 8px 8px 0; font-style: italic; }
  ul { padding-left: 1.6em; margin: 0.8em 0; }
  li { margin: 5px 0; }
  p { margin: 0.8em 0; }
  strong { color: #1a1a1a; }
  .presente { color: #2e7d32; font-weight: bold; }
  .assente { color: #c62828; font-weight: bold; }
  .footer { margin-top: 3em; padding-top: 1.2em; border-top: 1px solid #ddd; font-size: 0.82em; color: #999; font-family: sans-serif; text-align: center; }
  @media (max-width: 600px) { body { padding: 0 16px 40px; } .header { padding: 20px; } }
</style>
</head>
<body>
<div class="header">
  <h1>Report GEO/AEO — Casa Cavour Bertinoro</h1>
  <p>Data: ${data} &nbsp;|&nbsp; Generato automaticamente da RAB Analytics</p>
</div>
<div class="contenuto"><p>${html}</p></div>
<div class="footer">
  <p>Romagna Affitti Brevi — Sistema di monitoraggio GEO/AEO &nbsp;|&nbsp; casa-cavour.com</p>
</div>
</body>
</html>`;

return [{
  json: {
    reportHtml: documento,
    nomeFile: nomeFile,
    contenutoTestuale: testo
  }
}];
